const API_BASE = (process.env.EXPO_PUBLIC_IVX_API_BASE_URL || 'https://api.ivxholding.com').replace(/\/+$/, '');

/** JV deal enrichment attached to a feed video (matched via property_id / project_id). */
export interface FeedVideoDeal {
  id: string;
